    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    1,
    'Yoga Nidra - 1w 5x/wk',
    'yoga',
    5,
    60,
    ARRAY['Improve flexibility', 'Enhance body awareness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Yoga Nidra'
ON CONFLICT DO NOTHING;

